// v2.7: Store seen company keys from BOTH Seen Opportunities and Funding Alerts
// This fixes the issue where Dedup Register fails to populate Seen Opportunities

const staticData = $getWorkflowStaticData("global");
const seenKeys = new Set();

const items = $input.all();
for (const item of items) {
  // From Seen Opportunities: Key field
  const key = item.json.Key;
  if (key && key.startsWith("company:")) {
    seenKeys.add(key);
  }

  // From Funding Alerts: Company Name field (convert to key format)
  const companyName = item.json["Company Name"];
  if (companyName) {
    const normalizedKey = "company:" + companyName.toLowerCase().replace(/[^a-z0-9]/g, "");
    seenKeys.add(normalizedKey);
  }
}

staticData.seenCompanyKeys = Array.from(seenKeys);
console.log(`v2.7: Stored ${seenKeys.size} seen company keys (from Seen Opportunities + Funding Alerts)`);

return [{ json: { seenKeysLoaded: true, count: seenKeys.size } }];

const items = $input.all();
const results = [];
const vcName = 'Emergence Capital';
const seen = new Set();
const today = new Date().toISOString().split('T')[0];

for (const item of items) {
  try {
    let html = item.json.data || item.json.body || (typeof item.json === 'string' ? item.json : '');
    if (!html || html.length < 100) continue;

    const portfolioPattern = /<a[^>]*href=["']\/portfolio\/([^"']+)["'][^>]*>[\s\S]*?<\/a>/gi;
    let match;

    while ((match = portfolioPattern.exec(html)) !== null) {
      const slug = match[1];
      const content = match[0];

      let name = '';
      const altMatch = content.match(/alt=["']([^"']+)["']/i);
      if (altMatch) {
        name = altMatch[1].trim();
      } else {
        name = slug.split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
      }

      name = name.replace(/&amp;/g, '&');
      if (name.length < 2 || name.length > 50) continue;

      const key = name.toLowerCase().replace(/[^a-z0-9]/g, '');
      if (seen.has(key)) continue;
      seen.add(key);

      results.push({
        json: {
          'Company Name': name,
          'VC Firm': vcName,
          'Company Description': name + ' - Emergence Capital portfolio (Enterprise SaaS)',
          'Company URL': 'https://www.emcap.com/portfolio/' + slug,
          'Status': 'New',
          'First Seen Date': today,
          'Source': 'VC Portfolio'
        }
      });
    }
  } catch (e) {
    console.error('Emergence parse error:', e.message);
  }
}

return results.length ? results : [{ json: { _empty: true, _message: 'No companies found', vcName } }];

