}

return results.length ? results : [{ json: { _empty: true, _message: 'No companies found', vcName } }];

// v2.6: Filter using seen keys from staticData
// Seen keys were pre-loaded by Store Seen Keys node

const items = $input.all();
const staticData = $getWorkflowStaticData('global');

const seenKeysArray = staticData.seenCompanyKeys || [];
const seenKeys = new Set(seenKeysArray);

console.log(`Using ${seenKeys.size} seen company keys from staticData`);

const localSeen = new Set();
const newCompanies = [];
let skippedEmpty = 0;
let skippedDupe = 0;
let skippedSeen = 0;

for (const item of items) {
  if (item.json._empty) {
    skippedEmpty++;
    continue;
  }

  const name = item.json['Company Name'] || '';
  if (!name || name.length < 2) {
    skippedEmpty++;
    continue;
  }

  const localKey = name.toLowerCase().replace(/[^a-z0-9]/g, '');
  if (localSeen.has(localKey)) {
    skippedDupe++;
    continue;
  }
  localSeen.add(localKey);

  const dedupKey = 'company:' + localKey;
  if (seenKeys.has(dedupKey)) {
    skippedSeen++;
    continue;
  }

  newCompanies.push(item);
}

console.log(`Filter results: ${skippedEmpty} empty, ${skippedDupe} local dupes, ${skippedSeen} already seen, ${newCompanies.length} NEW`);

if (newCompanies.length === 0) {
  return [{ json: { _empty: true, _message: 'All companies already processed', skippedSeen, skippedDupe } }];
}

return newCompanies;
